package com.granpa.pumpselector;
import org.json.*;
public class PumpRecord {
 public String id="",model="",brand="",category="",phase="",hpText="",kwText="",stages="",headRangeText="",dischargeRangeText="",flowUnitOriginal="",size="",sheet="",title="",catalogueSectionText="",categoryDetail="",imageUrl="",normalizedCategory="OTHER",dataStatus="AUTO_CHECKED",dataNote="",variantLabel=""; public boolean selectable=true; public int page; public double hp=Double.NaN,kw=Double.NaN,minHead=Double.NaN,maxHead=Double.NaN,minFlowLPH=Double.NaN,maxFlowLPH=Double.NaN; public double[][] curve=new double[0][0];
 public static PumpRecord fromJson(JSONObject o){PumpRecord r=new PumpRecord(); r.id=o.optString("id"); r.model=o.optString("model"); r.brand=o.optString("brand"); r.category=o.optString("category"); r.phase=o.optString("phase"); r.hpText=o.optString("hpText"); r.kwText=o.optString("kwText"); r.stages=o.optString("stages"); r.headRangeText=o.optString("headRangeText"); r.dischargeRangeText=o.optString("dischargeRangeText"); r.flowUnitOriginal=o.optString("flowUnitOriginal"); r.size=o.optString("size"); r.sheet=o.optString("sheet"); r.title=o.optString("title"); r.catalogueSectionText=o.optString("catalogueSectionText"); r.categoryDetail=o.optString("categoryDetail"); r.imageUrl=o.optString("imageUrl"); r.normalizedCategory=o.optString("normalizedCategory","OTHER"); r.dataStatus=o.optString("dataStatus","AUTO_CHECKED"); r.dataNote=o.optString("dataNote"); r.variantLabel=o.optString("variantLabel"); r.selectable=o.optBoolean("selectable",true); r.page=o.optInt("page"); r.hp=o.optDouble("hp",Double.NaN); r.kw=o.optDouble("kw",Double.NaN); r.minHead=o.optDouble("minHead",Double.NaN); r.maxHead=o.optDouble("maxHead",Double.NaN); r.minFlowLPH=o.optDouble("minFlowLPH",Double.NaN); r.maxFlowLPH=o.optDouble("maxFlowLPH",Double.NaN); JSONArray a=o.optJSONArray("curve"); if(a!=null){r.curve=new double[a.length()][2]; for(int i=0;i<a.length();i++){JSONArray p=a.optJSONArray(i); if(p!=null){r.curve[i][0]=p.optDouble(0); r.curve[i][1]=p.optDouble(1);}}} return r;}
}